import React, { useCallback, useEffect, useState } from "react";
import { Container, TextField, Button, Typography, Grid, Link, Box } from '@mui/material';
import Layout from "../components/Layout";
import {
    GoogleReCaptchaProvider,
    useGoogleReCaptcha
} from 'react-google-recaptcha-v3';
import { login } from "../services/login/loginManager";
import useUser from "../storage/useUser";
import { getQuery } from "../utils/utils";

export default function Contato() {
    const [formData, setFormData] = useState({
        nome: '',
        email: '',
        telefone: '',
        assunto: '',
        mensagem: '',
    })
    const { login } = useUser();
    const YourReCaptchaComponent = () => {


        const handleChange = (e: any) => {
            const { name, value } = e.target;
            setFormData({ ...formData, [name]: value });
        };
        const { executeRecaptcha } = useGoogleReCaptcha();

        // Create an event handler so you can call the verification on button click event or form submit
        const handleReCaptchaVerify = useCallback(async () => {
            if (!executeRecaptcha) {
                console.log('Execute recaptcha not yet available');
                return;
            }

            const token = await executeRecaptcha('yourAction');
            console.log('token: ', token);
            console.log(formData);
            const jwt = getQuery('jwt');
            login(jwt || "", token).then((res) => {
                console.log('foi', res)
            }).catch((e) => {
                // TODO: toast erro
                console.log("e: ", e);
            })
        }, [executeRecaptcha]);

        const handleSubmit = async (e: any) => {
            e.preventDefault();
            handleReCaptchaVerify();
        };

        return <Container maxWidth="sm">
            <Box mt={5} mb={5}>
                <form onSubmit={handleSubmit}>
                    <Grid container spacing={2}>
                        <Grid item xs={12}>
                            <Typography variant="h4" align="center" gutterBottom>
                                Fale Conosco
                            </Typography>
                            <Typography variant="caption" display="block" gutterBottom>
                                Estamos aqui para ajudar! Por favor, preencha o formulário abaixo com sua dúvida, sugestão ou qualquer outra questão. Nossa equipe entrará em contato em até um dia útil.
                            </Typography>
                        </Grid>
                        <Grid item xs={12} sm={12}>
                            <TextField
                                fullWidth
                                label="Nome"
                                name="nome"
                                value={formData.nome}
                                onChange={handleChange}
                                required
                            />
                        </Grid>
                        <Grid item xs={12} sm={6}>
                            <TextField
                                fullWidth
                                label="Email"
                                type="email"
                                name="email"
                                value={formData.email}
                                onChange={handleChange}
                                required
                            />
                        </Grid>
                        <Grid item xs={12} sm={6}>
                            <TextField
                                fullWidth
                                label="Telefone (opcional)"
                                name="telefone"
                                value={formData.telefone}
                                onChange={handleChange}
                            />
                        </Grid>
                        <Grid item xs={12}>
                            <TextField
                                fullWidth
                                label="Assunto"
                                name="assunto"
                                value={formData.assunto}
                                onChange={handleChange}
                                required
                            />
                        </Grid>
                        <Grid item xs={12}>
                            <TextField
                                fullWidth
                                label="Mensagem"
                                multiline
                                rows={4}
                                inputProps={{ maxLength: 500 }}
                                name="mensagem"
                                value={formData.mensagem}
                                onChange={handleChange}
                                required
                            />
                            <Typography>
                                {`${formData.mensagem.length}/500`}
                            </Typography>
                        </Grid>
                        <Grid item xs={12}>
                            <Typography variant="body2" gutterBottom>
                                Ao enviar a mensagem, você concorda com a <Link href="/politica-de-privacidade">política de privacidade</Link>.
                            </Typography>
                        </Grid>
                        <Grid item xs={12}>
                            <Button type="submit" size="large" variant="contained" color="primary" fullWidth>
                                Enviar mensagem
                            </Button>
                        </Grid>
                    </Grid>
                </form>
            </Box>
        </Container>;
    };

    return (
        <Layout>
            <GoogleReCaptchaProvider reCaptchaKey="6LcWxTUpAAAAAO9Hj_S0HEHuuJnG07w3vF4amOR4">
                <YourReCaptchaComponent />
            </GoogleReCaptchaProvider>
        </Layout>
    );
}
